// Tokens de cor das variações (alinhados ao DSS)
const VARIANTS = {
  default: {
    antifraudeColor: "#a4a6a5",
    sansysColor: "#a4a6a5",
    iconColor: "#a4a6a5",
  },
  colored: {
    antifraudeColor: "#3c1377",
    sansysColor: "#1d4971",
    iconColor: "#3c1377",
  },
} as const;

export type LogoVariant = keyof typeof VARIANTS;

export interface SansysAntifraudeLogoProps {
  className?: string;
  /** Preset de cores. 'default' = monocromático neutro, 'colored' = cores da marca. */
  variant?: LogoVariant;
  /**
   * Cor do wordmark "Antifraude".
   * Sobrepõe a cor definida pelo variant.
   */
  antifraudeColor?: string;
  /**
   * Cor do wordmark "Sansys".
   * Sobrepõe a cor definida pelo variant.
   */
  sansysColor?: string;
  /**
   * Cor do ícone.
   * Sobrepõe a cor definida pelo variant.
   */
  iconColor?: string;
  /**
   * @deprecated Use `antifraudeColor` + `sansysColor` + `iconColor` para controle granular,
   * ou `variant` para presets. Mantido por compatibilidade.
   */
  color?: string;
}

export function SansysAntifraudeLogo({
  className = "h-12",
  variant = "default",
  antifraudeColor,
  sansysColor,
  iconColor,
  color, // legacy
}: SansysAntifraudeLogoProps) {
  const base = VARIANTS[variant];

  // Resolução de cor: prop explícita > legacy `color` > valor do variant
  const resolvedAntifraude = antifraudeColor ?? color ?? base.antifraudeColor;
  const resolvedSansys = sansysColor ?? color ?? base.sansysColor;
  const resolvedIcon = iconColor ?? color ?? base.iconColor;

  return (
    <svg
      className={className}
      viewBox="0 0 142 42"
      xmlns="http://www.w3.org/2000/svg"
      aria-label="Sansys Antifraude"
      role="img"
    >
      <g>
        {/* Wordmark: Antifraude */}
        <path fill={resolvedAntifraude} d={ANTIFRAUDE_PATH} />

        {/* Wordmark: Sansys */}
        <path fill={resolvedSansys} d={SANSYS_PATH} />

        {/* Ícone com estrelas anti-fraude */}
        <path fill={resolvedIcon} d={ICON_PATH} />
      </g>
    </svg>
  );
}
